  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `reservas_fixed_slot_id_foreign` (`fixed_slot_id`),
  KEY `reservas_recurrent_series_id_foreign` (`recurrent_series_id`),
